+type ReplaceRecur<TValue, TRecur> = TValue extends RecurSchema
+  ? TRecur
+  : TValue extends Map<infer TKey, infer TMapValue>
+    ? Map<ReplaceRecur<TKey, TRecur>, ReplaceRecur<TMapValue, TRecur>>
+    : TValue extends Set<infer TSetValue>
+      ? Set<ReplaceRecur<TSetValue, TRecur>>
+      : TValue extends readonly (infer TItem)[]
+        ? ReplaceRecur<TItem, TRecur>[]
+        : TValue extends object
+          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
+          : TValue;
