+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema: RecursiveSchema<TWrapped> = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    wrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return replaceRecur(this.wrapped, this)['~run'](dataset, config);
+    },
+  };
+  return schema;
+}
+
+/**
+ * Replaces recur placeholders in a schema.
+ *
+ * @param value The value to be copied.
+ * @param recur The recursive schema.
+ *
+ * @returns A copy with recur placeholders replaced.
+ *
+ * @internal
+ */
+function replaceRecur<TValue>(value: TValue, recur: BaseSchema<unknown, unknown, BaseIssue<unknown>>): TValue {
+  const values = new WeakMap<object, unknown>();
+
+  function copy<TCopyValue>(copyValue: TCopyValue): TCopyValue {
+    if (copyValue === Recur) {
+      return recur as TCopyValue;
+    }
+    if (!copyValue || typeof copyValue !== 'object') {
+      return copyValue;
+    }
+    const cachedValue = values.get(copyValue);
+    if (cachedValue) {
+      return cachedValue as TCopyValue;
+    }
+    if (Array.isArray(copyValue)) {
+      const copyValueArray: unknown[] = [];
+      values.set(copyValue, copyValueArray);
+      for (const item of copyValue) {
+        copyValueArray.push(copy(item));
+      }
+      return copyValueArray as TCopyValue;
+    }
+    if (
+      Object.getPrototypeOf(copyValue) !== Object.prototype &&
+      Object.getPrototypeOf(copyValue) !== null
+    ) {
+      return copyValue;
+    }
+    const copyValueObject = Object.create(Object.getPrototypeOf(copyValue));
+    values.set(copyValue, copyValueObject);
+    for (const key of Reflect.ownKeys(copyValue)) {
+      const descriptor = Object.getOwnPropertyDescriptor(copyValue, key);
+      if (descriptor && 'value' in descriptor) {
+        descriptor.value = copy(descriptor.value);
+      }
+      Object.defineProperty(copyValueObject, key, descriptor!);
+    }
+    return copyValueObject;
+  }
+
+  return copy(value);
+}
